import{_ as i,o as t,c as a,ag as e}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"[Client/App] Kho tính năng: Công cụ Tìm kiếm (Search Engine UX)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/03-kho-tinh-nang/tim-kiem-kham-pha/client-search-tools.md","filePath":"99-tham-khao/archive/03-kho-tinh-nang/tim-kiem-kham-pha/client-search-tools.md"}'),h={name:"99-tham-khao/archive/03-kho-tinh-nang/tim-kiem-kham-pha/client-search-tools.md"};function o(r,n,l,c,m,g){return t(),a("div",null,[...n[0]||(n[0]=[e('<h1 id="client-app-kho-tinh-nang-cong-cu-tim-kiem-search-engine-ux" tabindex="-1">[Client/App] Kho tính năng: Công cụ Tìm kiếm (Search Engine UX) <a class="header-anchor" href="#client-app-kho-tinh-nang-cong-cu-tim-kiem-search-engine-ux" aria-label="Permalink to &quot;[Client/App] Kho tính năng: Công cụ Tìm kiếm (Search Engine UX)&quot;">​</a></h1><p>Bộ công cụ tìm kiếm và lọc Tour dành cho khách hàng tìm kiếm tour nhanh nhất.</p><h2 id="_1-tim-kiem-đa-nang-omni-search-window" tabindex="-1">1. Tìm kiếm Đa năng (Omni-Search Window) <a class="header-anchor" href="#_1-tim-kiem-đa-nang-omni-search-window" aria-label="Permalink to &quot;1. Tìm kiếm Đa năng (Omni-Search Window)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Bàn phím gõ gợi ý (Fuzzy Search).</li><li>Hiển thị ảnh nhỏ (Thumbnail) trong danh sách kết quả gợi ý.</li></ul></li><li><strong>Phản hồi</strong>: Tốc độ phản hồi &lt; 200ms bằng cách sử dụng debounce gõ.</li></ul><h2 id="_2-bo-loc-thong-minh-smart-filters" tabindex="-1">2. Bộ lọc Thông minh (Smart Filters) <a class="header-anchor" href="#_2-bo-loc-thong-minh-smart-filters" aria-label="Permalink to &quot;2. Bộ lọc Thông minh (Smart Filters)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Lọc theo Vùng miền.</li><li>Lọc theo Khoảng giá (Price Slider).</li><li>Lọc theo Đánh giá của khách hàng (Rating).</li></ul></li></ul><h2 id="_3-ban-đo-tuong-tac-interactive-map-view" tabindex="-1">3. Bản đồ Tương tác (Interactive Map View) <a class="header-anchor" href="#_3-ban-đo-tuong-tac-interactive-map-view" aria-label="Permalink to &quot;3. Bản đồ Tương tác (Interactive Map View)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Hiển thị Pin tour/địa danh trên bản đồ.</li><li>Khi di chuyển bản đồ, hệ thống tự động fetch và hiển thị Tour tương ứng (Search per map move).</li></ul></li></ul><h2 id="_4-đac-ta-ket-qua-tim-kiem-serp-view" tabindex="-1">4. Đặc tả Kết quả Tìm kiếm (Serp View) <a class="header-anchor" href="#_4-đac-ta-ket-qua-tim-kiem-serp-view" aria-label="Permalink to &quot;4. Đặc tả Kết quả Tìm kiếm (Serp View)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Hiển thị dạng Grid/List linh hoạt.</li><li>Đánh dấu từ khóa khớp trong tên tour (Highlighting matches).</li></ul></li></ul><hr><p><em>Giao diện công cụ tìm kiếm tiện ích.</em></p>',12)])])}const k=i(h,[["render",o]]);export{u as __pageData,k as default};
